--------------------------- The Program ------------------
#include <sys/types.h>
#include <signal.h>
#include <pthread.h>
#include <unistd.h>
#include <stdio.h>
#include <err.h>

void *thr(void *a)
{
    int *ip = (int *)a;
    printf("started thread %d\n", *ip);
    pause();
    return 0;
}

int main(int argc, char **argv)
{
    const int THREADCOUNT =4;
    int i;
    pthread_t threads[THREADCOUNT];

    for (i =0; i < THREADCOUNT; i++)
       if (pthread_create(&threads[i], 0, thr, (void *)&i) != 0)
           errx(-1, "cannot create thread");

    sleep(1);
    kill(0, SIGBUS);
    return 0;
}

How-To-Repeat: Compile the program in the description section on a FreeBSD 6.3/32 bit
system.  Run it on a 6.3/64 bit system and attempt to look at the core
file ('info threads' for example)
